module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [7:0] multiplicand;
    reg [7:0] multiplier;
    reg [15:0] partial_product;
    reg [3:0] count;
    always @(*) begin

        if (count == 0) begin
            product = 16'd0;
            multiplicand = A;
            multiplier = B;
            partial_product = 16'd0;
            count = 4'd0;
        end

        else begin
            if (multiplier[0] == 1'b1) begin
                partial_product = partial_product + {8'd0, multiplicand};
            end
            multiplicand = multiplicand << 1;
            multiplier = multiplier >> 1;
        end
    end
    always @(posedge clk) begin
        if (count < 8) begin
            count <= count + 1;
        end
        else begin
            count <= count;
        end
    end
endmodule
